mapper.insert:

	SELECT SEQ_PLAN_DETAIL_NO.NEXTVAL FROM DUAL

INSERT INTO PLAN_DETAILS (
	PLAN_DETAIL_NO, PLAN_NO, PLACE_NO, USER_NO, PLAN_VISIT_ORDER, PLAN_MENO, DETAIL_START_DATE, DETAIL_END_DATE
) VALUES (
	#{planDetailNo}, #{planNo}, #{placeNo}, #{userNo}, #{planVisitOrder}, #{planMeno},
	#{detailStartDate,jdbcType=TIMESTAMP}, #{detailEndDate,jdbcType=TIMESTAMP}
)

mapper.select:
SELECT NVL(MAX(pd.plan_visit_order), 0)
FROM Plan_Details pd
WHERE pd.plan_no = #{value}

SELECT MAX(pd.plan_meno) KEEP (
	DENSE_RANK FIRST ORDER BY NVL(pd.plan_visit_order, 9999), pd.plan_detail_no
)
FROM Plan_Details pd
WHERE pd.plan_no = #{value}
  AND pd.plan_meno IS NOT NULL
